parameters.jsCode:
const video = $json.items?.[0];           // <-- THIS is the real video object
const isoRaw = video?.contentDetails?.duration;

const iso = String(isoRaw ?? "PT0S").trim();

const re = /^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/;
const m = re.exec(iso);

const hours = m?.[1] ? parseInt(m[1], 10) : 0;
const minutes = m?.[2] ? parseInt(m[2], 10) : 0;
const seconds = m?.[3] ? parseInt(m[3], 10) : 0;

return {
  // Flatten the video fields so the next nodes are easy:
  ...video,

  DurationSeconds: hours * 3600 + minutes * 60 + seconds
};
